using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Models;
using System;

namespace ContosoUniversity.Tests.Models
{
    [TestClass]
    public sealed class PersonTests
    {
        // Person is abstract, so we test via Student subclass
        private static Student CreatePerson(string lastName, string firstMidName)
        {
            return new Student
            {
                LastName = lastName,
                FirstMidName = firstMidName,
                EnrollmentDate = DateTime.Now
            };
        }

        [TestMethod]
        [DataRow("Smith", "John", "Smith, John")]
        [DataRow("O'Brien", "Mary", "O'Brien, Mary")]
        [DataRow("Doe", "Jane", "Doe, Jane")]
        [DataRow("Li", "Wei", "Li, Wei")]
        public void FullName_ReturnsLastNameCommaFirstMidName(string lastName, string firstMidName, string expected)
        {
            // Arrange
            var person = CreatePerson(lastName, firstMidName);

            // Act
            var fullName = person.FullName;

            // Assert
            Assert.AreEqual(expected, fullName);
        }

        [TestMethod]
        public void FullName_WithSingleCharacterNames_ReturnsCorrectFormat()
        {
            // Arrange
            var person = CreatePerson("A", "B");

            // Act
            var fullName = person.FullName;

            // Assert
            Assert.AreEqual("A, B", fullName);
        }

        [TestMethod]
        public void FullName_WithLongNames_ReturnsCorrectFormat()
        {
            // Arrange
            var lastName = new string('A', 50);
            var firstName = new string('B', 50);
            var person = CreatePerson(lastName, firstName);

            // Act
            var fullName = person.FullName;

            // Assert
            Assert.AreEqual($"{lastName}, {firstName}", fullName);
        }

        [TestMethod]
        public void FullName_ViaInstructor_ReturnsCorrectFormat()
        {
            // Arrange - verify FullName works through Instructor subclass too
            var instructor = new Instructor
            {
                LastName = "Kapoor",
                FirstMidName = "Candace",
                HireDate = DateTime.Now
            };

            // Act
            var fullName = instructor.FullName;

            // Assert
            Assert.AreEqual("Kapoor, Candace", fullName);
        }

        [TestMethod]
        public void ID_CanBeSetAndRetrieved()
        {
            // Arrange
            var person = CreatePerson("Test", "User");

            // Act
            person.ID = 42;

            // Assert
            Assert.AreEqual(42, person.ID);
        }

        [TestMethod]
        public void LastName_CanBeSetAndRetrieved()
        {
            // Arrange
            var person = CreatePerson("Original", "Name");

            // Act
            person.LastName = "Updated";

            // Assert
            Assert.AreEqual("Updated", person.LastName);
        }

        [TestMethod]
        public void FirstMidName_CanBeSetAndRetrieved()
        {
            // Arrange
            var person = CreatePerson("Last", "Original");

            // Act
            person.FirstMidName = "Updated";

            // Assert
            Assert.AreEqual("Updated", person.FirstMidName);
        }

        [TestMethod]
        [DataRow("García", "José", "García, José")]
        [DataRow("Müller", "Hans", "Müller, Hans")]
        public void FullName_WithUnicodeCharacters_ReturnsCorrectFormat(string lastName, string firstMidName, string expected)
        {
            // Arrange
            var person = CreatePerson(lastName, firstMidName);

            // Act
            var fullName = person.FullName;

            // Assert
            Assert.AreEqual(expected, fullName);
        }

        [TestMethod]
        public void FullName_WithSpacesInNames_ReturnsCorrectFormat()
        {
            // Arrange
