using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        #region Constructor Tests

        [TestMethod]
        public void Constructor_SetsPageIndex()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 2, 3);

            // Assert
            Assert.AreEqual(2, list.PageIndex);
        }

        [TestMethod]
        public void Constructor_SetsTotalPages_CeilingDivision()
        {
            // Arrange - 10 items with page size 3 => ceil(10/3) = 4
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 10, 1, 3);

            // Assert
            Assert.AreEqual(4, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_SetsTotalPages_EvenDivision()
        {
            // Arrange - 9 items with page size 3 => ceil(9/3) = 3
            var list = new PaginatedList<int>(new List<int> { 1, 2, 3 }, 9, 1, 3);

            // Assert
            Assert.AreEqual(3, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_AddsItemsToList()
        {
            // Arrange
            var items = new List<int> { 10, 20, 30 };

            // Act
            var list = new PaginatedList<int>(items, 100, 1, 3);

            // Assert
            Assert.AreEqual(3, list.Count);
            Assert.AreEqual(10, list[0]);
            Assert.AreEqual(20, list[1]);
            Assert.AreEqual(30, list[2]);
        }

        [TestMethod]
        public void Constructor_WithEmptyItems_CreatesEmptyList()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int>(), 0, 1, 10);

            // Assert
            Assert.AreEqual(0, list.Count);
            Assert.AreEqual(1, list.PageIndex);
            Assert.AreEqual(0, list.TotalPages);
        }

        [TestMethod]
        public void Constructor_SingleItem_SinglePage()
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int> { 42 }, 1, 1, 10);

            // Assert
            Assert.AreEqual(1, list.Count);
            Assert.AreEqual(1, list.TotalPages);
        }

        #endregion

        #region TotalPages Calculation Tests

        [TestMethod]
        [DataRow(0, 10, 0)]
        [DataRow(1, 10, 1)]
        [DataRow(10, 10, 1)]
        [DataRow(11, 10, 2)]
        [DataRow(20, 10, 2)]
        [DataRow(21, 10, 3)]
        [DataRow(100, 10, 10)]
        [DataRow(101, 10, 11)]
        public void TotalPages_CalculatesCorrectly(int count, int pageSize, int expectedTotalPages)
        {
            // Arrange & Act
            var list = new PaginatedList<int>(new List<int>(), count, 1, pageSize);

            // Assert
            Assert.AreEqual(expectedTotalPages, list.TotalPages);
        }

        #endregion

        #region HasPreviousPage Tests

        [TestMethod]
        public void HasPreviousPage_OnFirstPage_ReturnsFalse()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

            // Assert
            Assert.IsFalse(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_OnSecondPage_ReturnsTrue()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);

            // Assert
            Assert.IsTrue(list.HasPreviousPage);
        }

        [TestMethod]
        public void HasPreviousPage_OnLastPage_ReturnsTrue()
        {
            // Arrange
            var list = new PaginatedList<int>(new List<int> { 1 }, 30, 3, 10);

            // Assert
            Assert.IsTrue(list.HasPreviousPage);
        }

        #endregion

        #region HasNextPage Tests

        [TestMethod]
        public void HasNextPage_WhenPageIndexLessThanTotalPages_ReturnsTrue()
        {
            // Arrange - page 1 of 2
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 1, 5);

            // Assert
            Assert.IsTrue(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_WhenPageIndexEqualsTotalPages_ReturnsFalse()
        {
            // Arrange - page 2 of 2
            var list = new PaginatedList<int>(new List<int> { 1 }, 10, 2, 5);

            // Assert
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_OnSinglePage_ReturnsFalse()
        {
            // Arrange - page 1 of 1
            var list = new PaginatedList<int>(new List<int> { 1 }, 3, 1, 5);

            // Assert
            Assert.IsFalse(list.HasNextPage);
        }

        [TestMethod]
        public void HasNextPage_OnEmptyList_ReturnsFalse()
        {
            // Arrange - page 1 of 0
            var list = new PaginatedList<int>(new List<int>(), 0, 1, 5);

            // Assert
            Assert.IsFalse(list.HasNextPage);
        }

        #endregion

        #region Create Static Method Tests

        [TestMethod]
        public void Create_ReturnsCorrectPageOfItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 20).AsQueryable();

            // Act - page 2, size 5 => items 6..10
            var result = PaginatedList<int>.Create(source, 2, 5);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(6, result[0]);
            Assert.AreEqual(10, result[4]);
            Assert.AreEqual(2, result.PageIndex);
            Assert.AreEqual(4, result.TotalPages);
        }

        [TestMethod]
        public void Create_FirstPage_ReturnsFirstItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 15).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 5);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(5, result[4]);
            Assert.AreEqual(1, result.PageIndex);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsTrue(result.HasNextPage);
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 12).AsQueryable();

            // Act - page 3, size 5 => items 11..12 (only 2 items)
            var result = PaginatedList<int>.Create(source, 3, 5);

            // Assert
            Assert.AreEqual(2, result.Count);
            Assert.AreEqual(11, result[0]);
            Assert.AreEqual(12, result[1]);
            Assert.IsTrue(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = Enumerable.Empty<int>().AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 5);

            // Assert
            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(1, result.PageIndex);
            Assert.AreEqual(0, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_SinglePage_AllItemsFit()
        {
            // Arrange
            var source = Enumerable.Range(1, 3).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 10);

            // Assert
            Assert.AreEqual(3, result.Count);
            Assert.AreEqual(1, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_ExactPageSize_NoPartialPage()
        {
            // Arrange - 10 items, page size 5 => exactly 2 pages
            var source = Enumerable.Range(1, 10).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, 1, 5);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(2, result.TotalPages);
            Assert.IsTrue(result.HasNextPage);
        }

        [TestMethod]
        public void Create_WithStringType_WorksCorrectly()
        {
            // Arrange
            var source = new[] { "alpha", "beta", "gamma", "delta", "epsilon" }.AsQueryable();

            // Act
            var result = PaginatedList<string>.Create(source, 1, 3);

            // Assert
            Assert.AreEqual(3, result.Count);
            Assert.AreEqual("alpha", result[0]);
            Assert.AreEqual("gamma", result[2]);
            Assert.AreEqual(2, result.TotalPages);
        }

        #endregion
    }
}

using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _service;

        [TestInitialize]
        public void TestInitialize()
        {
            _service = new NotificationService();
            // Drain the static queue to prevent cross-test interference
            while (_service.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void TestCleanup()
        {
            _service.Dispose();
            // Drain queue again after test
            using var cleanupService = new NotificationService();
            while (cleanupService.ReceiveNotification() != null) { }
        }

        #region SendNotification and ReceiveNotification Tests

        [TestMethod]
        public void SendNotification_EnqueuesNotification_ReceiveDequeuesIt()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithUserName_SetsCreatedBy()
        {
            // Arrange & Act
            _service.SendNotification("Course", "101", EntityOperation.UPDATE, "admin");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("admin", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            // Arrange & Act
            _service.SendNotification("Course", "101", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_MultipleMessages_DequeuedInOrder()
        {
            // Arrange
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", EntityOperation.UPDATE);
            _service.SendNotification("Department", "3", EntityOperation.DELETE);

            // Act & Assert - FIFO order
            var first = _service.ReceiveNotification();
            Assert.AreEqual("Student", first.EntityType);

            var second = _service.ReceiveNotification();
            Assert.AreEqual("Course", second.EntityType);

            var third = _service.ReceiveNotification();
            Assert.AreEqual("Department", third.EntityType);
        }

        #endregion

        #region Message Generation Tests

        [TestMethod]
        public void SendNotification_CreateOperation_WithoutDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Student", "42", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateOperation_WithoutDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Course", "101", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("Course (ID: 101) has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteOperation_WithoutDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Department", "5", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("Department (ID: 5) has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_CreateOperation_WithDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Student", "42", "John Smith", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Student 'John Smith' has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateOperation_WithDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteOperation_WithDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithNullDisplayName_UsesIdFormat()
        {
            // Arrange & Act
            _service.SendNotification("Student", "7", (string)null, EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Student (ID: 7) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithEmptyDisplayName_UsesIdFormat()
        {
            // Arrange & Act
            _service.SendNotification("Student", "7", "", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Student (ID: 7) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdFormat()
        {
            // Arrange & Act
            _service.SendNotification("Student", "7", "   ", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Student (ID: 7) has been created", notification.Message);
        }

        #endregion

        #region ReceiveNotification - Empty Queue Tests

        [TestMethod]
        public void ReceiveNotification_WhenQueueIsEmpty_ReturnsNull()
        {
            // Act
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNull(notification);
        }

        [TestMethod]
        public void ReceiveNotification_AfterAllDequeued_ReturnsNull()
        {
            // Arrange
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.ReceiveNotification(); // dequeue the one item

            // Act
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNull(notification);
        }

        #endregion

        #region MarkAsRead Tests

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // Act & Assert - should not throw (it's a no-op)
            _service.MarkAsRead(1);
            _service.MarkAsRead(0);
            _service.MarkAsRead(-1);
            _service.MarkAsRead(int.MaxValue);
        }

        #endregion

        #region Queue Cap Tests

        [TestMethod]
        public void SendNotification_ExceedingMaxQueueLength_CapsAtMaximum()
        {
            // Arrange - send more than 500 notifications
            for (int i = 0; i < 510; i++)
            {
                _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            // Act - count remaining items by draining
            int count = 0;
            while (_service.ReceiveNotification() != null)
            {
                count++;
            }

            // Assert - should not exceed 500
            Assert.IsTrue(count <= 500, $"Queue count was {count}, expected <= 500");
        }

        #endregion

        #region Dispose Tests

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            // Act & Assert - should not throw
            _service.Dispose();
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            // Act & Assert - should not throw on multiple dispose calls
            _service.Dispose();
            _service.Dispose();
        }

        #endregion

        #region Notification Properties Tests

        [TestMethod]
        public void SendNotification_SetsCreatedAtToRecentTime()
        {
            // Arrange
            var before = System.DateTime.Now.AddSeconds(-1);

            // Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();
            var after = System.DateTime.Now.AddSeconds(1);

            // Assert
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before, $"CreatedAt {notification.CreatedAt} should be >= {before}");
            Assert.IsTrue(notification.CreatedAt <= after, $"CreatedAt {notification.CreatedAt} should be <= {after}");
        }

        [TestMethod]
        public void SendNotification_SetsIsReadToFalse()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_SetsOperationAsString()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("DELETE", notification.Operation);
        }

        #endregion
    }
}

