using Microsoft.VisualStudio.TestTools.UnitTesting;
using ContosoUniversity.Services;
using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _service;

        [TestInitialize]
        public void TestInitialize()
        {
            _service = new NotificationService();
            // Drain the static queue to prevent cross-test interference
            while (_service.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void TestCleanup()
        {
            _service.Dispose();
            // Drain queue again after test
            using var cleanupService = new NotificationService();
            while (cleanupService.ReceiveNotification() != null) { }
        }

        #region SendNotification and ReceiveNotification Tests

        [TestMethod]
        public void SendNotification_EnqueuesNotification_ReceiveDequeuesIt()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("1", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_WithUserName_SetsCreatedBy()
        {
            // Arrange & Act
            _service.SendNotification("Course", "101", EntityOperation.UPDATE, "admin");
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("admin", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_WithoutUserName_DefaultsToSystem()
        {
            // Arrange & Act
            _service.SendNotification("Course", "101", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void SendNotification_MultipleMessages_DequeuedInOrder()
        {
            // Arrange
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.SendNotification("Course", "2", EntityOperation.UPDATE);
            _service.SendNotification("Department", "3", EntityOperation.DELETE);

            // Act & Assert - FIFO order
            var first = _service.ReceiveNotification();
            Assert.AreEqual("Student", first.EntityType);

            var second = _service.ReceiveNotification();
            Assert.AreEqual("Course", second.EntityType);

            var third = _service.ReceiveNotification();
            Assert.AreEqual("Department", third.EntityType);
        }

        #endregion

        #region Message Generation Tests

        [TestMethod]
        public void SendNotification_CreateOperation_WithoutDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Student", "42", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Student (ID: 42) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateOperation_WithoutDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Course", "101", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("Course (ID: 101) has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteOperation_WithoutDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Department", "5", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("Department (ID: 5) has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_CreateOperation_WithDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Student", "42", "John Smith", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Student 'John Smith' has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_UpdateOperation_WithDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Course", "101", "Chemistry", EntityOperation.UPDATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("Course 'Chemistry' has been updated", notification.Message);
        }

        [TestMethod]
        public void SendNotification_DeleteOperation_WithDisplayName_GeneratesCorrectMessage()
        {
            // Arrange & Act
            _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("Department 'Engineering' has been deleted", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithNullDisplayName_UsesIdFormat()
        {
            // Arrange & Act
            _service.SendNotification("Student", "7", (string)null, EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Student (ID: 7) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithEmptyDisplayName_UsesIdFormat()
        {
            // Arrange & Act
            _service.SendNotification("Student", "7", "", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Student (ID: 7) has been created", notification.Message);
        }

        [TestMethod]
        public void SendNotification_WithWhitespaceDisplayName_UsesIdFormat()
        {
            // Arrange & Act
            _service.SendNotification("Student", "7", "   ", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.AreEqual("New Student (ID: 7) has been created", notification.Message);
        }

        #endregion

        #region ReceiveNotification - Empty Queue Tests

        [TestMethod]
        public void ReceiveNotification_WhenQueueIsEmpty_ReturnsNull()
        {
            // Act
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNull(notification);
        }

        [TestMethod]
        public void ReceiveNotification_AfterAllDequeued_ReturnsNull()
        {
            // Arrange
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            _service.ReceiveNotification(); // dequeue the one item

            // Act
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNull(notification);
        }

        #endregion

        #region MarkAsRead Tests

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // Act & Assert - should not throw (it's a no-op)
            _service.MarkAsRead(1);
            _service.MarkAsRead(0);
            _service.MarkAsRead(-1);
            _service.MarkAsRead(int.MaxValue);
        }

        #endregion

        #region Queue Cap Tests

        [TestMethod]
        public void SendNotification_ExceedingMaxQueueLength_CapsAtMaximum()
        {
            // Arrange - send more than 500 notifications
            for (int i = 0; i < 510; i++)
            {
                _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            // Act - count remaining items by draining
            int count = 0;
            while (_service.ReceiveNotification() != null)
            {
                count++;
            }

            // Assert - should not exceed 500
            Assert.IsTrue(count <= 500, $"Queue count was {count}, expected <= 500");
        }

        #endregion

        #region Dispose Tests

        [TestMethod]
        public void Dispose_DoesNotThrow()
        {
            // Act & Assert - should not throw
            _service.Dispose();
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            // Act & Assert - should not throw on multiple dispose calls
            _service.Dispose();
            _service.Dispose();
        }

        #endregion

        #region Notification Properties Tests

        [TestMethod]
        public void SendNotification_SetsCreatedAtToRecentTime()
        {
            // Arrange
            var before = System.DateTime.Now.AddSeconds(-1);

            // Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();
            var after = System.DateTime.Now.AddSeconds(1);

            // Assert
            Assert.IsNotNull(notification);
            Assert.IsTrue(notification.CreatedAt >= before, $"CreatedAt {notification.CreatedAt} should be >= {before}");
            Assert.IsTrue(notification.CreatedAt <= after, $"CreatedAt {notification.CreatedAt} should be <= {after}");
        }

        [TestMethod]
        public void SendNotification_SetsIsReadToFalse()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.IsFalse(notification.IsRead);
        }

        [TestMethod]
        public void SendNotification_SetsOperationAsString()
        {
            // Arrange & Act
            _service.SendNotification("Student", "1", EntityOperation.DELETE);
            var notification = _service.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("DELETE", notification.Operation);
        }

        #endregion
    }
}

