using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Moq;
using System;
using System.Collections.Generic;
using System.Linq;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext CreateContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        [TestInitialize]
        public void Setup()
        {
            var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
        }

        private StudentsController CreateController(SchoolContext context)
        {
            var controller = new StudentsController(context);
            controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(),
                Mock.Of<ITempDataProvider>());
            return controller;
        }

        private void SeedStudents(SchoolContext context, int count = 3)
        {
            for (int i = 1; i <= count; i++)
            {
                context.Students.Add(new Student
                {
                    LastName = $"Last{i:D2}",
                    FirstMidName = $"First{i:D2}",
                    EnrollmentDate = new DateTime(2023, i, 15)
                });
            }
            context.SaveChanges();
        }

        #region Index Tests

        [TestMethod]
        public void Index_DefaultSort_ReturnsStudentsOrderedByLastNameAsc()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            context.Students.AddRange(
                new Student { LastName = "Zulu", FirstMidName = "A", EnrollmentDate = DateTime.Today },
                new Student { LastName = "Alpha", FirstMidName = "B", EnrollmentDate = DateTime.Today },
                new Student { LastName = "Mike", FirstMidName = "C", EnrollmentDate = DateTime.Today }
            );
            context.SaveChanges();

            using var readContext = CreateContext(dbName);
            var controller = CreateController(readContext);

            // Act
            var result = controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
            Assert.AreEqual("Alpha", model[0].LastName);
            Assert.AreEqual("Mike", model[1].LastName);
            Assert.AreEqual("Zulu", model[2].LastName);
        }

        [TestMethod]
        public void Index_NameDescSort_ReturnsStudentsOrderedByLastNameDesc()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            context.Students.AddRange(
                new Student { LastName = "Alpha", FirstMidName = "A", EnrollmentDate = DateTime.Today },
                new Student { LastName = "Zulu", FirstMidName = "B", EnrollmentDate = DateTime.Today },
                new Student { LastName = "Mike", FirstMidName = "C", EnrollmentDate = DateTime.Today }
            );
            context.SaveChanges();

            using var readContext = CreateContext(dbName);
            var controller = CreateController(readContext);

            // Act
            var result = controller.Index("name_desc", null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Zulu", model[0].LastName);
            Assert.AreEqual("Mike", model[1].LastName);
            Assert.AreEqual("Alpha", model[2].LastName);
        }

        [TestMethod]
        public void Index_DateSort_ReturnsStudentsOrderedByDateAsc()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            context.Students.AddRange(
                new Student { LastName = "C", FirstMidName = "C", EnrollmentDate = new DateTime(2025, 3, 1) },
                new Student { LastName = "A", FirstMidName = "A", EnrollmentDate = new DateTime(2023, 1, 1) },
                new Student { LastName = "B", FirstMidName = "B", EnrollmentDate = new DateTime(2024, 2, 1) }
            );
            context.SaveChanges();

            using var readContext = CreateContext(dbName);
            var controller = CreateController(readContext);

            // Act
            var result = controller.Index("Date", null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(new DateTime(2023, 1, 1), model[0].EnrollmentDate);
            Assert.AreEqual(new DateTime(2024, 2, 1), model[1].EnrollmentDate);
            Assert.AreEqual(new DateTime(2025, 3, 1), model[2].EnrollmentDate);
        }

        [TestMethod]
        public void Index_DateDescSort_ReturnsStudentsOrderedByDateDesc()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            context.Students.AddRange(
                new Student { LastName = "A", FirstMidName = "A", EnrollmentDate = new DateTime(2023, 1, 1) },
                new Student { LastName = "B", FirstMidName = "B", EnrollmentDate = new DateTime(2024, 2, 1) },
                new Student { LastName = "C", FirstMidName = "C", EnrollmentDate = new DateTime(2025, 3, 1) }
            );
            context.SaveChanges();

            using var readContext = CreateContext(dbName);
            var controller = CreateController(readContext);

            // Act
            var result = controller.Index("date_desc", null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(new DateTime(2025, 3, 1), model[0].EnrollmentDate);
            Assert.AreEqual(new DateTime(2024, 2, 1), model[1].EnrollmentDate);
            Assert.AreEqual(new DateTime(2023, 1, 1), model[2].EnrollmentDate);
        }

        [TestMethod]
        public void Index_SearchByLastName_ReturnsMatchingStudents()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            context.Students.AddRange(
                new Student { LastName = "Smith", FirstMidName = "John", EnrollmentDate = DateTime.Today },
                new Student { LastName = "Johnson", FirstMidName = "Jane", EnrollmentDate = DateTime.Today },
                new Student { LastName = "Smithson", FirstMidName = "Bob", EnrollmentDate = DateTime.Today }
            );
            context.SaveChanges();

            using var readContext = CreateContext(dbName);
            var controller = CreateController(readContext);

            // Act
            var result = controller.Index(null, null, "Smith", null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);
            Assert.IsTrue(model.All(s => s.LastName.Contains("Smith")));
        }

        [TestMethod]
        public void Index_SearchByFirstName_ReturnsMatchingStudents()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            context.Students.AddRange(
                new Student { LastName = "Doe", FirstMidName = "Jane", EnrollmentDate = DateTime.Today },
                new Student { LastName = "Smith", FirstMidName = "John", EnrollmentDate = DateTime.Today },
                new Student { LastName = "Brown", FirstMidName = "Janet", EnrollmentDate = DateTime.Today }
            );
            context.SaveChanges();

            using var readContext = CreateContext(dbName);
            var controller = CreateController(readContext);

            // Act
            var result = controller.Index(null, null, "Jan", null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);
            Assert.IsTrue(model.All(s => s.FirstMidName.Contains("Jan")));
        }

        [TestMethod]
        public void Index_NoSearch_ReturnsAllStudents()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            SeedStudents(context);

            using var readContext = CreateContext(dbName);
            var controller = CreateController(readContext);

            // Act
            var result = controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
        }

        [TestMethod]
        public void Index_Pagination_Page1_ReturnsFirstPageStudents()
        {
            // Arrange (pageSize is 10, so seed 12 students)
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            for (int i = 1; i <= 12; i++)
            {
                context.Students.Add(new Student
                {
                    LastName = $"Student{i:D2}",
                    FirstMidName = $"First{i:D2}",
                    EnrollmentDate = DateTime.Today
                });
            }
            context.SaveChanges();

            using var readContext = CreateContext(dbName);
            var controller = CreateController(readContext);

            // Act
            var result = controller.Index(null, null, null, 1) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(10, model.Count);
            Assert.AreEqual(1, model.PageIndex);
            Assert.IsTrue(model.HasNextPage);
            Assert.IsFalse(model.HasPreviousPage);
        }

        [TestMethod]
        public void Index_Pagination_Page2_ReturnsRemainingStudents()
        {
            // Arrange (pageSize is 10, so seed 12 students)
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            for (int i = 1; i <= 12; i++)
            {
                context.Students.Add(new Student
                {
                    LastName = $"Student{i:D2}",
                    FirstMidName = $"First{i:D2}",
                    EnrollmentDate = DateTime.Today
                });
            }
            context.SaveChanges();

            using var readContext = CreateContext(dbName);
            var controller = CreateController(readContext);

            // Act
            var result = controller.Index(null, null, null, 2) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Count);
            Assert.AreEqual(2, model.PageIndex);
            Assert.IsFalse(model.HasNextPage);
            Assert.IsTrue(model.HasPreviousPage);
        }

        [TestMethod]
        public void Index_NullPage_DefaultsToPage1()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            SeedStudents(context);

            using var readContext = CreateContext(dbName);
            var controller = CreateController(readContext);

            // Act
            var result = controller.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_NewSearchString_ResetsPageTo1()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            SeedStudents(context);

            using var readContext = CreateContext(dbName);
            var controller = CreateController(readContext);

            // Act - passing a searchString (non-null) should force page=1
            var result = controller.Index(null, null, "Last", 5) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);
            context.Students.AddRange(
                new Student { LastName = "Smith", FirstMidName = "John", EnrollmentDate = DateTime.Today },
