            Assert.AreEqual("Smith", model[0].LastName);
        }

        #endregion

        #region Details Tests

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Arrange
            using var context = CreateContext();
            var controller = CreateController(context);

            // Act
