using Microsoft.VisualStudio.TestTools.UnitTesting;
using Microsoft.EntityFrameworkCore;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using System;
using System.Linq;

namespace ContosoUniversity.Tests.Data
{
    [TestClass]
    public sealed class DbInitializerTests
    {
        private SchoolContext CreateContext(string dbName = null)
        {
            dbName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: dbName)
                .Options;
            return new SchoolContext(options);
        }

        [TestInitialize]
        public void Setup()
        {
            var svc = new NotificationService();
            while (svc.ReceiveNotification() != null) { }
        }

        [TestMethod]
        public void Initialize_Seeds8Students()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);

            // Act
            DbInitializer.Initialize(context);

            // Assert
            using var verifyContext = CreateContext(dbName);
            Assert.AreEqual(8, verifyContext.Students.Count());
        }

        [TestMethod]
        public void Initialize_Seeds5Instructors()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);

            // Act
            DbInitializer.Initialize(context);

            // Assert
            using var verifyContext = CreateContext(dbName);
            Assert.AreEqual(5, verifyContext.Instructors.Count());
        }

        [TestMethod]
        public void Initialize_Seeds4Departments()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);

            // Act
            DbInitializer.Initialize(context);

            // Assert
            using var verifyContext = CreateContext(dbName);
            Assert.AreEqual(4, verifyContext.Departments.Count());
        }

        [TestMethod]
        public void Initialize_Seeds7Courses()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);

            // Act
            DbInitializer.Initialize(context);

            // Assert
            using var verifyContext = CreateContext(dbName);
            Assert.AreEqual(7, verifyContext.Courses.Count());
        }

        [TestMethod]
        public void Initialize_Seeds3OfficeAssignments()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);

            // Act
            DbInitializer.Initialize(context);

            // Assert
            using var verifyContext = CreateContext(dbName);
            Assert.AreEqual(3, verifyContext.OfficeAssignments.Count());
        }

        [TestMethod]
        public void Initialize_Seeds11Enrollments()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);

            // Act
            DbInitializer.Initialize(context);

            // Assert
            using var verifyContext = CreateContext(dbName);
            Assert.AreEqual(11, verifyContext.Enrollments.Count());
        }

        [TestMethod]
        public void Initialize_CalledTwice_DoesNotDuplicateData()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);

            // Act
            DbInitializer.Initialize(context);

            // Call Initialize a second time on same database
            using var context2 = CreateContext(dbName);
            DbInitializer.Initialize(context2);

            // Assert - counts should remain the same
            using var verifyContext = CreateContext(dbName);
            Assert.AreEqual(8, verifyContext.Students.Count());
            Assert.AreEqual(5, verifyContext.Instructors.Count());
            Assert.AreEqual(4, verifyContext.Departments.Count());
            Assert.AreEqual(7, verifyContext.Courses.Count());
        }

        [TestMethod]
        public void Initialize_StudentDataMatchesExpectedNames()
        {
            // Arrange
            var dbName = Guid.NewGuid().ToString();
            using var context = CreateContext(dbName);

            // Act
            DbInitializer.Initialize(context);

            // Assert
            using var verifyContext = CreateContext(dbName);
            var studentNames = verifyContext.Students
                .OrderBy(s => s.LastName)
                .Select(s => s.LastName)
                .ToList();

            Assert.AreEqual(8, studentNames.Count);
            CollectionAssert.Contains(studentNames, "Alexander");
            CollectionAssert.Contains(studentNames, "Alonso");
            CollectionAssert.Contains(studentNames, "Anand");
            CollectionAssert.Contains(studentNames, "Barzdukas");
            CollectionAssert.Contains(studentNames, "Li");
            CollectionAssert.Contains(studentNames, "Justice");
            CollectionAssert.Contains(studentNames, "Norman");
            CollectionAssert.Contains(studentNames, "Olivetto");
        }
    }
}

